  ('generalpolice-f3743df6-moex-00232', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '依司法院大法官解釋，下列何者不違反比例原則？', '["對於應迴避而不迴避之公職人員，未衡酌情節輕微情形，一律處以100萬元以上之罰鍰", "對於遮斷器已開始放下仍強行闖越平交道，並因而肇事之汽車駕駛人，吊銷其駕駛執照", "計程車駕駛人，在執業期間犯竊盜罪，經法院判決有期徒刑確定者，廢止其執業登記，並吊銷其駕駛執照", "臺灣地區人民已有子女者，不予認可收養其配偶之大陸地區子女"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00233', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '如行政院環境保護署擬代行地方政府處理事業廢棄物非法棄置場址之清理，下列敘述何者錯誤？', '["須地方自治團體依法應作為而不作為，致嚴重危害公益或妨礙政務正常運作", "原則上須行政院環境保護署先命地方自治團體於一定期限內作為而仍不作為", "代行處理所支出之費用，應由行政院環境保護署負擔", "地方自治團體認為行政院環境保護署代行處理之決定違法時，得提起行政救濟 2701"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00234', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '稱契約自由者，謂當事人得以契約形成私法法律關係。下列何者不是契約自由之內容？', '["締約自由", "撤銷自由", "內容自由", "當事人自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00235', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '甲有A屋一棟，委任乙管理之，但未授與乙代理權。乙本於該委任而僱用丙粉刷A屋工資新臺幣（以下 同）20萬元，其又以每月租金20萬元將A屋出租予丁。依民法規定，下列敘述何者錯誤？', '["若乙已支付工資20萬元予丙，乙得請求甲償還之，並付支出時起之利息", "若乙尚未支付工資予丙，乙不得請求甲代為清償", "乙得基於租賃契約，向丁按月請求給付租金", "甲就乙自丁所收取之租金，得請求乙交付之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00236', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '下列那一種刑之宣告，有假釋規定之適用？', '["有期徒刑3月", "拘役30日", "無期徒刑", "死刑執行前"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00237', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '不具公務員身分之甲與公務員乙共同實行收受賄賂之行為，關於甲刑責之敘述，下列何者正確？', '["甲應論以公務員收受賄賂罪之教唆犯，得減輕其刑", "甲應論以公務員收受賄賂罪之共同正犯，得減輕其刑", "甲應論以公務員收受賄賂罪之幫助犯，得減輕其刑", "甲應論以公務員收受賄賂罪之間接正犯，得減輕其刑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00238', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', 'A公開發行公司連年虧損，但有重建更生之可能，故擬聲請重整，其請教律師關於公司重整的規定，下列 敘述何者正確？', '["持有公司已發行股份總數百分之五之股東得提出聲請", "有相當於公司已發行股份總數金額百分之十以上之公司債權人得提出聲請", "A公司為聲請者，應經股東會特別決議", "A公司為聲請者，應經董事會普通決議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00239', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '甲為食品製造暨進口商，乙為其經銷商。下列敘述何者錯誤？', '["甲為消費者保護法所稱之企業經營者", "甲就其製造之商品對消費者或第三人所生之損害，應負無過失責任", "乙若將甲製造之食品自行分裝，就消費者或第三人所生之損害，應負無過失責任", "甲就其進口之食品對消費者或第三人所生之損害，應負重大過失責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00240', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '下列有關扶養之敘述，何者正確？', '["離婚後，未成年子女由母親向法院請求變更子女姓氏為母姓獲准，則父親可拒絕給付未成年子女的扶養費", "年邁的父母若不能維持生活而無謀生能力，方可請求成年子女扶養", "19歲的未成年子女若有不服管教、毆打父母，則父母可向法院請求減輕或免除扶養義務", "離婚後，為人父母者對未成年子女的扶養義務，並非一人一半，而係視雙方經濟能力分擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00241', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-110-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '甲將新購的手機，交給乙製作手機包膜。乙製作完畢，但於乙將手機交付甲前，該手機卻因不可抗力而滅 失。依民法規定，下列有關報酬之敘述，何者正確？', '["乙仍然可以向甲請求報酬", "乙不能向甲請求報酬", "乙必須再購買同款手機，製作包膜完畢，交還給甲。但只能請求一次報酬", "乙必須再購買同款手機，製作包膜完畢，交還給甲。但可以請求兩次報酬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "305", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL)
